"""
Integration test configuration.
All integration tests share this client fixture, which uses a low-cost model
and a short max_tokens limit to keep API spend manageable.
"""
import os
import pytest
import anthropic

# Use the cheapest model in integration tests — we are testing code structure,
# not model capability. Model capability is covered by the eval suite.
_TEST_MODEL    = "claude-haiku-4-5-20251001"
_TEST_MAX_TOKENS = 150

@pytest.fixture(scope="module")
def client():
    return anthropic.Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])

@pytest.fixture(scope="module")
def test_model():
    return _TEST_MODEL

@pytest.fixture(scope="module")
def test_max_tokens():
    return _TEST_MAX_TOKENS
